import { fabric } from 'fabric';

export const createParabola = (startPoint, endPoint, color, width) => {
  const points = [];
  const a = (endPoint.y - startPoint.y) / Math.pow(endPoint.x - startPoint.x, 2);
  const b = -2 * a * startPoint.x;
  const c = startPoint.y - a * Math.pow(startPoint.x, 2) - b * startPoint.x;

  for (let x = startPoint.x; x <= endPoint.x; x += 1) {
    const y = a * Math.pow(x, 2) + b * x + c;
    points.push({ x, y });
  }

  return new fabric.Polyline(points, {
    stroke: color,
    strokeWidth: width,
    fill: 'transparent',
    selectable: false,
  });
};

export const createHyperbola = (startPoint, endPoint, color, width) => {
  const points = [];
  const a = Math.abs(endPoint.x - startPoint.x) / 2;
  const b = Math.abs(endPoint.y - startPoint.y) / 2;
  const centerX = (startPoint.x + endPoint.x) / 2;
  const centerY = (startPoint.y + endPoint.y) / 2;

  for (let t = -Math.PI; t <= Math.PI; t += 0.1) {
    const x = centerX + a * Math.cosh(t);
    const y = centerY + b * Math.sinh(t);
    points.push({ x, y });
  }

  return new fabric.Polyline(points, {
    stroke: color,
    strokeWidth: width,
    fill: 'transparent',
    selectable: false,
  });
};

export const createCycloid = (startPoint, endPoint, color, width) => {
  const points = [];
  const radius = Math.sqrt(
    Math.pow(endPoint.x - startPoint.x, 2) + Math.pow(endPoint.y - startPoint.y, 2)
  ) / (2 * Math.PI);

  for (let t = 0; t <= 2 * Math.PI; t += 0.1) {
    const x = startPoint.x + radius * (t - Math.sin(t));
    const y = startPoint.y + radius * (1 - Math.cos(t));
    points.push({ x, y });
  }

  return new fabric.Polyline(points, {
    stroke: color,
    strokeWidth: width,
    fill: 'transparent',
    selectable: false,
  });
};

export const createEpicycloid = (startPoint, endPoint, color, width) => {
  const points = [];
  const R = Math.sqrt(
    Math.pow(endPoint.x - startPoint.x, 2) + Math.pow(endPoint.y - startPoint.y, 2)
  );
  const r = R / 4;

  for (let t = 0; t <= 2 * Math.PI; t += 0.1) {
    const x = startPoint.x + (R + r) * Math.cos(t) - r * Math.cos(((R + r) / r) * t);
    const y = startPoint.y + (R + r) * Math.sin(t) - r * Math.sin(((R + r) / r) * t);
    points.push({ x, y });
  }

  return new fabric.Polyline(points, {
    stroke: color,
    strokeWidth: width,
    fill: 'transparent',
    selectable: false,
  });
};

export const createHypocycloid = (startPoint, endPoint, color, width) => {
  const points = [];
  const R = Math.sqrt(
    Math.pow(endPoint.x - startPoint.x, 2) + Math.pow(endPoint.y - startPoint.y, 2)
  );
  const r = R / 4;

  for (let t = 0; t <= 2 * Math.PI; t += 0.1) {
    const x = startPoint.x + (R - r) * Math.cos(t) + r * Math.cos(((R - r) / r) * t);
    const y = startPoint.y + (R - r) * Math.sin(t) - r * Math.sin(((R - r) / r) * t);
    points.push({ x, y });
  }

  return new fabric.Polyline(points, {
    stroke: color,
    strokeWidth: width,
    fill: 'transparent',
    selectable: false,
  });
};

export const createSpiral = (startPoint, endPoint, color, width) => {
  const points = [];
  const maxRadius = Math.sqrt(
    Math.pow(endPoint.x - startPoint.x, 2) + Math.pow(endPoint.y - startPoint.y, 2)
  );
  const a = 0.5;
  const b = 0.5;

  for (let t = 0; t <= 4 * Math.PI; t += 0.1) {
    const r = a + b * t;
    if (r > maxRadius) break;
    const x = startPoint.x + r * Math.cos(t);
    const y = startPoint.y + r * Math.sin(t);
    points.push({ x, y });
  }

  return new fabric.Polyline(points, {
    stroke: color,
    strokeWidth: width,
    fill: 'transparent',
    selectable: false,
  });
};

export const createMirrorImage = (startPoint, endPoint, color, width) => {
  const points = [];
  const dx = endPoint.x - startPoint.x;
  const dy = endPoint.y - startPoint.y;
  const length = Math.sqrt(dx * dx + dy * dy);
  const angle = Math.atan2(dy, dx);

  for (let t = 0; t <= 1; t += 0.1) {
    const x = startPoint.x + dx * t;
    const y = startPoint.y + dy * t;
    points.push({ x, y });
    points.push({
      x: x + length * Math.cos(angle + Math.PI / 2),
      y: y + length * Math.sin(angle + Math.PI / 2),
    });
  }

  return new fabric.Polyline(points, {
    stroke: color,
    strokeWidth: width,
    fill: 'transparent',
    selectable: false,
  });
};

// Shape definitions with their parameters
export const shapeDefinitions = {
  select: { text: 'Select Figure...', params: [] },
  point: { text: 'POINT', params: [ {name:'x', label:'X:'}, {name:'y', label:'Y:'} ] },
  line: { text: 'LINE', params: [ {name:'x1', label:'X1:'}, {name:'y1', label:'Y1:'}, {name:'x2', label:'X2:'}, {name:'y2', label:'Y2:'} ] },
  circle: { text: 'CIRCLE', params: [ {name:'centerX', label:'Center X:'}, {name:'centerY', label:'Center Y:'}, {name:'radius', label:'Radius'} ] },
  rectangle: { text: 'RECTANGLE', params: [ {name:'centerX', label:'Center X:'}, {name:'centerY', label:'Center Y:'}, {name:'width', label:'Width'}, {name:'height', label:'Height'} ] },
  triangle: { text: 'TRIANGLE', params: [ {name:'x1', label:'X1:'}, {name:'y1', label:'Y1:'}, {name:'x2', label:'X2:'}, {name:'y2', label:'Y2:'}, {name:'x3', label:'X3:'}, {name:'y3', label:'Y3:'} ] },
  ellipse: { text: 'ELLIPSE', params: [ {name:'centerX', label:'Center X:'}, {name:'centerY', label:'Center Y:'}, {name:'radiusX', label:'Radius X:'}, {name:'radiusY', label:'Radius Y:'} ] },
};

export const defaultShape = 'select';

// Drawing functions
export const drawGridAndAxes = (ctx, width, height) => {
  ctx.fillStyle = '#fff';
  ctx.fillRect(0, 0, width, height);
  
  // Grid
  ctx.save();
  ctx.strokeStyle = '#e0e0e0';
  ctx.lineWidth = 0.5;
  const gridSpacing = 20;
  for (let x = 0; x <= width; x += gridSpacing) {
    ctx.beginPath(); ctx.moveTo(x, 0); ctx.lineTo(x, height); ctx.stroke();
  }
  for (let y = 0; y <= height; y += gridSpacing) {
    ctx.beginPath(); ctx.moveTo(0, y); ctx.lineTo(width, y); ctx.stroke();
  }
  
  // Axes
  ctx.strokeStyle = '#888';
  ctx.lineWidth = 1.5;
  ctx.beginPath(); ctx.moveTo(width/2, 0); ctx.lineTo(width/2, height); ctx.stroke();
  ctx.beginPath(); ctx.moveTo(0, height/2); ctx.lineTo(width, height/2); ctx.stroke();
  ctx.restore();
};

export const drawFigure = (ctx, figure, centerX, centerY) => {
  ctx.save();
  ctx.strokeStyle = figure.color;
  ctx.lineWidth = figure.lineWidth;
  ctx.fillStyle = figure.color;

  switch (figure.type) {
    case 'point':
      ctx.beginPath();
      ctx.arc(centerX + figure.params.x, centerY - figure.params.y, 3, 0, 2 * Math.PI);
      ctx.fill();
      break;

    case 'line':
      ctx.beginPath();
      ctx.moveTo(centerX + figure.params.x1, centerY - figure.params.y1);
      ctx.lineTo(centerX + figure.params.x2, centerY - figure.params.y2);
      ctx.stroke();
      break;

    case 'circle':
      ctx.beginPath();
      ctx.arc(centerX + figure.params.centerX, centerY - figure.params.centerY, figure.params.radius, 0, 2 * Math.PI);
      ctx.stroke();
      break;

    case 'rectangle':
      ctx.beginPath();
      ctx.rect(
        centerX + figure.params.centerX - figure.params.width/2,
        centerY - figure.params.centerY - figure.params.height/2,
        figure.params.width,
        figure.params.height
      );
      ctx.stroke();
      break;

    case 'triangle':
      ctx.beginPath();
      ctx.moveTo(centerX + figure.params.x1, centerY - figure.params.y1);
      ctx.lineTo(centerX + figure.params.x2, centerY - figure.params.y2);
      ctx.lineTo(centerX + figure.params.x3, centerY - figure.params.y3);
      ctx.closePath();
      ctx.stroke();
      break;

    case 'ellipse':
      ctx.beginPath();
      ctx.ellipse(
        centerX + figure.params.centerX,
        centerY - figure.params.centerY,
        figure.params.radiusX,
        figure.params.radiusY,
        0, 0, 2 * Math.PI
      );
      ctx.stroke();
      break;
  }
  ctx.restore();
};
